#!/usr/bin/env node
/**
 * ============================================================================
 * SPIKE-SCOPE ARTIFACT — WO-005 phase-0 throwaway helper
 * ============================================================================
 * Generates the three latency-benchmark fixtures defined in plan.md Step 8:
 *   - spike-10.json   — 10 vars, 2 modes (Light/Dark), smoke test (Step 5)
 *   - spike-100.json  — 100 vars, single mode Default, latency mid-point
 *   - spike-400.json  — 400 vars, single mode Default, latency stress point
 *
 * Hex values are derived deterministically from token names via FNV-1a 32-bit
 * hashing (low 24 bits → hex). Determinism matters so that re-runs of the
 * benchmark next sprint or in CI produce comparable BenchRecord output AND
 * visual mismatches in the Figma variables panel are caught immediately
 * (e.g. if `color.primary.50` doesn't show `#<expected>`, the parser broke).
 *
 * SURVIVAL after spike close (per plan.md Step 14):
 *   - This script + the generated JSON files + scripts/fixtures/README.md
 *     stay in `.github/Sprint 1/WO-005-…/scripts/` as durable reference.
 *   - `src/spike/fixtures.ts` is also emitted (for the UI dropdown) and is
 *     throwaway — it lives on `spike/phase-0` only and is deleted with the
 *     branch. Sprint 2 (WO-007/008/009) does NOT lift from it.
 * ============================================================================
 */

import { mkdirSync, writeFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(__dirname, '..', '..', '..', '..');
const fixturesDir = resolve(__dirname, 'fixtures');
const spikeFixturesTs = resolve(repoRoot, 'src', 'spike', 'fixtures.ts');

const THROWAWAY_FIXTURE_BANNER =
  'SPIKE-SCOPE — WO-005 phase-0 throwaway fixture. ' +
  'Generated by .github/Sprint 1/WO-005-…/scripts/generate-fixtures.mjs. ' +
  'Hex values are deterministic FNV-1a hashes of token names. ' +
  'Do NOT lift into Sprint 2 — WO-007/008/009 rebuild canonical fixtures from real design systems.';

/**
 * FNV-1a 32-bit hash → 24-bit RGB hex. Deterministic, no deps, ES2017-safe.
 * The seed string fully determines the output color.
 */
function hashHex(seed) {
  let h = 0x811c9dc5 >>> 0;
  for (let i = 0; i < seed.length; i++) {
    h ^= seed.charCodeAt(i);
    h = Math.imul(h, 0x01000193) >>> 0;
  }
  return '#' + (h & 0xffffff).toString(16).padStart(6, '0');
}

const SHADES_10 = [50, 100, 200, 300, 400, 500, 600, 700, 800, 900];
const SHADES_20 = [
  25, 50, 75, 100, 150, 200, 250, 300, 350, 400, 450, 500, 550, 600, 650, 700, 750, 800, 850, 900,
];
const FAMILIES_10 = [
  'primary',
  'secondary',
  'neutral',
  'accent',
  'success',
  'warning',
  'error',
  'info',
  'surface',
  'brand',
];
const FAMILIES_20 = [
  ...FAMILIES_10,
  'slate',
  'gray',
  'zinc',
  'stone',
  'red',
  'orange',
  'amber',
  'lime',
  'green',
  'teal',
];

/**
 * Build the per-leaf codeSyntax block. Matches the shape in
 * research/spike-runbook.md §1.1 (web/android use dashes; ios uses .Palette dot-path).
 */
function codeSyntaxFor(family, shade) {
  return {
    WEB: `var(--color-${family}-${shade})`,
    ANDROID: `color-${family}-${shade}`,
    iOS: `.Palette.${family}.${shade}`,
  };
}

function singleModeLeaf(family, shade) {
  const tokenPath = `color.${family}.${shade}`;
  return {
    $type: 'color',
    $value: hashHex(tokenPath),
    $extensions: {
      fighub: {
        codeSyntax: codeSyntaxFor(family, shade),
      },
    },
  };
}

function twoModeLeaf(family, shade) {
  const tokenPath = `color.${family}.${shade}`;
  const lightHex = hashHex(`${tokenPath}:light`);
  const darkHex = hashHex(`${tokenPath}:dark`);
  return {
    $type: 'color',
    // $value mirrors the first mode (Light) so single-mode consumers still see a sane value.
    $value: lightHex,
    $extensions: {
      fighub: {
        modes: { light: lightHex, dark: darkHex },
        codeSyntax: codeSyntaxFor(family, shade),
      },
    },
  };
}

function buildFixture({ families, shades, makeLeaf }) {
  const fixture = {
    $comment: THROWAWAY_FIXTURE_BANNER,
    $schema: 'https://design-tokens.github.io/community-group/format/',
    color: {},
  };
  for (const family of families) {
    fixture.color[family] = {};
    for (const shade of shades) {
      fixture.color[family][shade] = makeLeaf(family, shade);
    }
  }
  return fixture;
}

const fixture10 = buildFixture({
  families: ['primary'],
  shades: SHADES_10,
  makeLeaf: twoModeLeaf,
});

const fixture100 = buildFixture({
  families: FAMILIES_10,
  shades: SHADES_10,
  makeLeaf: singleModeLeaf,
});

const fixture400 = buildFixture({
  families: FAMILIES_20,
  shades: SHADES_20,
  makeLeaf: singleModeLeaf,
});

mkdirSync(fixturesDir, { recursive: true });

function leafCount(fixture) {
  let n = 0;
  for (const family of Object.keys(fixture.color)) {
    n += Object.keys(fixture.color[family]).length;
  }
  return n;
}

const fixtures = [
  { name: 'spike-10', data: fixture10, expected: 10 },
  { name: 'spike-100', data: fixture100, expected: 100 },
  { name: 'spike-400', data: fixture400, expected: 400 },
];

for (const { name, data, expected } of fixtures) {
  const actual = leafCount(data);
  if (actual !== expected) {
    throw new Error(`${name} produced ${actual} leaves, expected ${expected}`);
  }
  const outPath = resolve(fixturesDir, `${name}.json`);
  writeFileSync(outPath, JSON.stringify(data, null, 2) + '\n', 'utf8');
  console.log(`wrote ${outPath} (${actual} tokens)`);
}

/**
 * Emit src/spike/fixtures.ts — string-form fixture map for the UI dropdown.
 * Stringified (not imported as JSON) so the dropdown can drop the exact text
 * into the textarea verbatim, preserving formatting for the user to inspect/edit
 * before clicking Push.
 *
 * SPIKE-SCOPE — this TS file is throwaway and disappears when `spike/phase-0`
 * is deleted. Sprint 2 does NOT lift from it.
 */
const tsLines = [
  '// ============================================================================',
  '// SPIKE-SCOPE — WO-005 phase-0 throwaway helper',
  '// ============================================================================',
  '// Auto-generated by .github/Sprint 1/WO-005-…/scripts/generate-fixtures.mjs.',
  '// Do NOT edit by hand — re-run the generator. Do NOT lift into Sprint 2.',
  '// ============================================================================',
  '',
  "export type SpikeFixtureId = '10' | '100' | '400';",
  '',
  'export const SPIKE_FIXTURES: Record<SpikeFixtureId, string> = {',
];
for (const { name, data } of fixtures) {
  const id = name.replace('spike-', '');
  const jsonStr = JSON.stringify(data, null, 2);
  // Build a clean ES2017-safe escaped template literal (avoid backticks + ${ collisions).
  const escaped = jsonStr.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${');
  tsLines.push(`  '${id}': \`${escaped}\`,`);
}
tsLines.push('};');
tsLines.push('');

mkdirSync(dirname(spikeFixturesTs), { recursive: true });
writeFileSync(spikeFixturesTs, tsLines.join('\n'), 'utf8');
console.log(`wrote ${spikeFixturesTs}`);
